  ('judicial-792a7dff-moex-00084', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-0e802df0', 'sub-judicial-792a7dff-07', NULL, 'essay', '如管理階層拒絕查核人員寄發詢證函，查核人員應進行那些程序？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "bd0c13a1220f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00085', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-0e802df0', 'sub-judicial-792a7dff-07', NULL, 'essay', '查核人員於執行那些工作時，可能需要查核人員專家之協助？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "bd0c13a1220f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00086', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-0e802df0', 'sub-judicial-792a7dff-07', NULL, 'essay', '查核人員使用電腦輔助查核技術之主要步驟包括那些？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "bd0c13a1220f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00087', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-69fcaee1', 'sub-judicial-792a7dff-03', NULL, 'essay', 'A、B 二人合夥經營蚵仔麵線小吃攤，並以 A 為執行業務合夥人，由 A
負責全部的蚵仔麵線經營事宜。某次A在煮麵線時，操作爐火不慎，燙
傷路人C，致使C受傷。又有一次，A因為和顧客D發生口角，遂在麵
線中添加瀉藥，致使D身體不適。問：另一合夥人 B，是否必須對 C及
D的損害負責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "9e881b074565", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法與刑法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL),
  ('judicial-792a7dff-moex-00088', 'judicial-792a7dff', 'judicial-792a7dff-moex-111-69fcaee1', 'sub-judicial-792a7dff-03', NULL, 'essay', 'A 係國內著名的公益社團法人，B 係其董事代表人。在召開今年度的社
員大會上，經過激烈的爭吵及抗爭，由 C 獲選為新任董事代表人，此事
並廣為媒體報導。但 B不願承認選舉結果，乃遲遲阻擾社團法人董事變
更登記的完成。為使 A 社團法人能夠繼續順利運作，故 C 以 A 社團法
人董事名義，即刻進行相關的締約事宜商議，並與知情之 D締約。詎料，
A 社團法人嗣後請求 D 履約時，D 以 C 締約時未經登記為新任董事為
由，拒絕履約。問：D之拒絕，有無理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:57+00:00", "source_pdf_sha1": "9e881b074565", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "106", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法與刑法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官財經事務組"}'::jsonb, NULL)
